import json
import pathlib
import subprocess

import pytest

AC_UID = "ac04_quoted_metachar_matrix_v2"
AC_TYPE = "hook"

REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
HOOK_PATH = REPO_ROOT / "hooks" / "pretool-bash-safety.sh"
STABLE_STDERR_TOKEN = "bulk-commit-sentinel-write"

_FLAG = "/tmp/claude-bulk-allowed-testsid.flag"


def _run_hook_with_payload(hook_path, command):
    payload = {
        "tool_name": "Bash",
        "agent_id": "qa-test",
        "tool_input": {"command": command},
    }
    proc = subprocess.run(
        ["bash", str(hook_path)],
        input=json.dumps(payload),
        capture_output=True,
        text=True,
        timeout=10,
    )
    return proc.returncode, proc.stdout, proc.stderr


# (case, command, expected_exit, expect_token_present)
ALLOW_MATRIX = [
    ("a_quoted_pipe",       f"grep -E 'foo|bar' {_FLAG}",   0, False),
    ("b_quoted_semicolon",  f"grep -E 'a;b' {_FLAG}",       0, False),
    ("c_quoted_andand",     f"grep -E 'a && b' {_FLAG}",    0, False),
    ("d_quoted_cmdsub",     f"grep -E '$(cmd)' {_FLAG}",    0, False),
    ("e_quoted_redirect",   f"grep -E '>file' {_FLAG}",     0, False),
    ("f_quoted_procsub",    f"grep -E '<(cmd)' {_FLAG}",    0, False),
]

DENY_MATRIX = [
    ("g_active_cmdsub_unquoted",     f"cat {_FLAG} $(cmd)",        2, True),
    ("h_active_cmdsub_doublequoted", f'cat {_FLAG} "$(cmd)"',      2, True),
    ("i_active_procsub_read",        f"cat {_FLAG} <(cmd)",        2, True),
    ("j_active_procsub_write",       f"cat {_FLAG} >(cmd)",        2, True),
]

ALL_CASES = ALLOW_MATRIX + DENY_MATRIX


@pytest.mark.parametrize(
    "case,command,expected_exit,expect_token",
    ALL_CASES,
    ids=[row[0] for row in ALL_CASES],
)
def test_AC_04_quoted_metachar_matrix(
    case, command, expected_exit, expect_token
):
    """
    GIVEN: commands invoking read-only grep against the protected flag with
           various shell metacharacters in patterns, plus active subshell/
           process-sub forms.
    WHEN:  Layer 1.F evaluates each command using the canonical tokenizer.
    THEN:  ALLOW (rc=0) when metacharacter is enclosed in single quotes
           inside an argument to a pure-read verb; DENY (rc=2) when the
           metacharacter is an active unquoted or double-quoted subshell/
           process-sub form.
    """
    assert HOOK_PATH.exists(), f"hook missing at {HOOK_PATH}"

    rc, _stdout, stderr = _run_hook_with_payload(HOOK_PATH, command)

    assert rc == expected_exit, (
        f"[{case}] expected exit {expected_exit}, got {rc}. "
        f"command={command!r}, stderr={stderr!r}"
    )

    token_present = STABLE_STDERR_TOKEN in stderr
    assert token_present is expect_token, (
        f"[{case}] expected stderr token '{STABLE_STDERR_TOKEN}' "
        f"present={expect_token}, got present={token_present}. "
        f"stderr={stderr!r}"
    )
